'use client';

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { grantAdminRole } from '@/app/actions';
import { Loader2, ShieldCheck, ShieldAlert } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useUser } from '@/firebase';

export default function GrantAdminPage() {
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<{ success: boolean; message: string } | null>(null);
  const { toast } = useToast();
  const { user, isUserLoading } = useUser();

  const handleGrantAdmin = async () => {
    setIsLoading(true);
    setResult(null);

    const emailToMakeAdmin = 'stakithire@gmail.com';

    // For this one-time setup, we only need to ensure the user is logged in as the correct email.
    // The server action itself is what performs the privileged operation.
    if (isUserLoading) {
        toast({
            variant: "destructive",
            title: "Please wait",
            description: "User data is still loading. Please try again in a moment.",
        });
        setIsLoading(false);
        return;
    }
    
    if (!user || user.email !== emailToMakeAdmin) {
        toast({
            variant: "destructive",
            title: "Authentication Error",
            description: `You must be logged in as ${emailToMakeAdmin} to perform this action.`,
        });
        setResult({ success: false, message: `Please log in as ${emailToMakeAdmin}.`});
        setIsLoading(false);
        return;
    }

    try {
      const response = await grantAdminRole(emailToMakeAdmin);
      setResult(response);
      if (response.success) {
        toast({
          title: 'Success!',
          description: response.message,
        });
      } else {
        toast({
          variant: 'destructive',
          title: 'Error',
          description: response.message,
        });
      }
    } catch (error: any) {
      const errorMessage = error.message || 'An unexpected error occurred.';
      setResult({ success: false, message: errorMessage });
      toast({
        variant: 'destructive',
        title: 'Operation Failed',
        description: errorMessage,
      });
    } finally {
      setIsLoading(false);
    }
  };

  if (isUserLoading) {
    return (
        <div className="flex justify-center items-center h-48">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
            <p className="ml-4 text-muted-foreground">Loading user data...</p>
        </div>
    )
  }

  return (
    <div className="container mx-auto max-w-2xl py-12">
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl font-headline">Grant Admin Privileges</CardTitle>
          <CardDescription>
            This page is for the one-time setup of the initial administrator account.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="p-4 rounded-lg border bg-blue-50 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
            <p className="font-semibold">Email to be granted Admin access:</p>
            <p className="font-mono text-lg">stakithire@gmail.com</p>
          </div>

          <div className="space-y-4">
              <p>
                <span className='font-bold'>Step 1:</span> Click the button below to assign the 'admin' role to the user account. You must be logged in as this user to proceed.
              </p>
            <Button onClick={handleGrantAdmin} disabled={isLoading} className="w-full">
              {isLoading ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ) : (
                <ShieldCheck className="mr-2 h-4 w-4" />
              )}
              Grant Admin Role
            </Button>
          </div>

            {result && (
              <div className={`p-4 rounded-lg border ${result.success ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'}`}>
                <div className="flex items-start gap-3">
                  {result.success ? <ShieldCheck className="h-5 w-5" /> : <ShieldAlert className="h-5 w-5" />}
                  <div>
                    <p className="font-bold">{result.success ? 'Success' : 'Error'}</p>
                    <p>{result.message}</p>
                  </div>
                </div>
              </div>
            )}

            {result?.success && (
                <div className='space-y-4 pt-4 border-t'>
                    <p>
                        <span className='font-bold'>Step 2:</span> To apply the new role, please sign out and sign back in again.
                    </p>
                    <p className='text-sm text-muted-foreground'>
                        This forces the application to fetch your new authentication token, which includes your admin privileges. Afterwards, the "Admin" link will appear in the footer.
                    </p>
                </div>
            )}
        </CardContent>
      </Card>
    </div>
  );
}
